import './App.css';
import { useState } from 'react';
import one from './images/1g.svg';
import two from './images/2g.svg';
import three from './images/3g.svg';
import four from './images/4g.svg';
import five from './images/5g.svg';
import six from './images/6g.svg';
import seven from './images/7g.svg';
import eight from './images/8g.svg';
import nine from './images/9g.svg';
import ten from './images/10g.svg';
import eleven from './images/11g.svg';
import twelve from './images/12g.svg';
import thirteen from './images/13g.svg';
import background from './images/1.jpg';

function App() {
    let [index, changeindex] = useState(1);
    let [bgpic, setbgpic] = useState(one);

    function changebg() {
        if (index === 13) {
            return;
        }
        changeindex(index + 1);

        switch (index) {
            case 1:
                setbgpic(one);
                break;
            case 2:
                setbgpic(two);
                break;
            case 3:
                setbgpic(three);
                break;
            case 4:
                setbgpic(four);
                break;
            case 5:
                setbgpic(five);
                break;
            case 6:
                setbgpic(six);
                break;
            case 7:
                setbgpic(seven);
                break;
            case 8:
                setbgpic(eight);
                break;
            case 9:
                setbgpic(nine);
                break;
            case 10:
                setbgpic(ten);
                break;
            case 11:
                setbgpic(eleven);
                break;
            case 12:
                setbgpic(twelve);
                break;
            case 13:
                setbgpic(thirteen);
                break;
            default:
                setbgpic(one);
        }
    }

    return (
        <div onClick={changebg} style={{
            backgroundImage: `url(${background})`,
        }}></div>
    );
}

export default App;
